import 'dart:io';

void main() {
  final file = File('d:/Codes/Android/math_quiz_app/lib/screens/about_screen.dart');
  final content = file.readAsStringSync();
  
  // Find where _AboutScreenState ends
  const searchStr = 'class _LinkItem {';
  final index = content.indexOf(searchStr);
  
  if (index != -1) {
    final before = content.substring(0, index).trimRight();
    final after = content.substring(index);
    
    // Check if before ends with } } or just }
    // We want to insert our method BEFORE the class closing brace.
    
    final lastBraceIndex = before.lastIndexOf('}');
    if (lastBraceIndex != -1) {
      final finalBefore = before.substring(0, lastBraceIndex);
      
      final newContent = '$finalBefore\n\n  Widget _buildMigrationPanel(BuildContext context) {\n    final theme = Theme.of(context);\n    final colorScheme = theme.colorScheme;\n\n    return Padding(\n      padding: const EdgeInsets.only(left: 16, right: 16, top: 16),\n      child: Container(\n        padding: const EdgeInsets.all(20),\n        decoration: BoxDecoration(\n          gradient: LinearGradient(\n            colors: [\n              colorScheme.primaryContainer.withValues(alpha: 0.4),\n              colorScheme.secondaryContainer.withValues(alpha: 0.2),\n            ],\n            begin: Alignment.topLeft,\n            end: Alignment.bottomRight,\n          ),\n          borderRadius: BorderRadius.circular(24),\n          border: Border.all(color: colorScheme.primary.withValues(alpha: 0.1)),\n        ),\n        child: Column(\n          crossAxisAlignment: CrossAxisAlignment.start,\n          children: [\n            Row(\n              children: [\n                Container(\n                  padding: const EdgeInsets.all(8),\n                  decoration: BoxDecoration(\n                    color: colorScheme.primary,\n                    shape: BoxShape.circle,\n                  ),\n                  child: const Icon(Icons.auto_awesome,\n                      color: Colors.white, size: 18),\n                ),\n                const SizedBox(width: 12),\n                const Expanded(\n                  child: Text(\n                    \'升级至 Uni-Sync 4.0\',\n                    style: TextStyle(fontWeight: FontWeight.bold, fontSize: 16),\n                  ),\n                ),\n                if (_migrationCompleted)\n                  const Icon(Icons.check_circle, color: Colors.green, size: 24),\n              ],\n            ),\n            const SizedBox(height: 16),\n            if (!_isMigrating && !_migrationCompleted) ...[\n              const Text(\n                \'您的数据目前存储在旧版引擎中。升级到 Uni-Sync 4.0 (SQLite) 将获得极速搜索、离线同步和更稳定的数据保护。\',\n                style: TextStyle(fontSize: 13, height: 1.4),\n              ),\n              const SizedBox(height: 20),\n              SizedBox(\n                width: double.infinity,\n                child: FilledButton.icon(\n                  onPressed: _startMigration,\n                  icon: const Icon(Icons.rocket_launch_rounded),\n                  label: const Text(\'立即开始极速迁移\'),\n                  style: FilledButton.styleFrom(\n                    padding: const EdgeInsets.symmetric(vertical: 12),\n                    shape: RoundedRectangleBorder(\n                        borderRadius: BorderRadius.circular(12)),\n                  ),\n                ),\n              ),\n            ] else if (_isMigrating || _migrationCompleted) ...[\n              Row(\n                mainAxisAlignment: MainAxisAlignment.spaceBetween,\n                children: [\n                  Text(\n                    _migrationStage,\n                    style: TextStyle(\n                        fontSize: 13,\n                        color: colorScheme.primary,\n                        fontWeight: FontWeight.w500),\n                  ),\n                  Text(\n                    \'成功: \$_migrationSuccessCount | 失败: \${_migrationErrors.length}\',\n                    style: TextStyle(fontSize: 11, color: colorScheme.outline),\n                  ),\n                ],\n              ),\n              const SizedBox(height: 12),\n              ClipRRect(\n                borderRadius: BorderRadius.circular(8),\n                child: LinearProgressIndicator(\n                  value: _migrationProgress,\n                  minHeight: 8,\n                  backgroundColor: colorScheme.primary.withValues(alpha: 0.1),\n                ),\n              ),\n              if (_migrationErrors.isNotEmpty) ...[\n                const SizedBox(height: 12),\n                Container(\n                  padding: const EdgeInsets.all(12),\n                  decoration: BoxDecoration(\n                    color: Colors.orange.withValues(alpha: 0.1),\n                    borderRadius: BorderRadius.circular(12),\n                  ),\n                  child: Column(\n                    crossAxisAlignment: CrossAxisAlignment.start,\n                    children: [\n                      Row(\n                        children: [\n                          const Icon(Icons.warning_amber_rounded,\n                              color: Colors.orange, size: 16),\n                          const SizedBox(width: 8),\n                          Text(\n                            \'迁移发现 \${_migrationErrors.length} 条异常\',\n                            style: const TextStyle(\n                                color: Colors.orange,\n                                fontSize: 12,\n                                fontWeight: FontWeight.bold),\n                          ),\n                        ],\n                      ),\n                      const SizedBox(height: 4),\n                      Text(\n                        _migrationErrors.take(3).join(\'\\n\'),\n                        style: const TextStyle(\n                            color: Colors.orange,\n                            fontSize: 10,\n                            fontFamily: \'monospace\'),\n                        maxLines: 3,\n                        overflow: TextOverflow.ellipsis,\n                      ),\n                      if (_migrationErrors.length > 3)\n                        const Text(\'...\',\n                            style: TextStyle(color: Colors.orange)),\n                    ],\n                  ),\n                ),\n              ],\n              if (_migrationCompleted && _migrationErrors.isEmpty) ...[\n                const SizedBox(height: 12),\n                const Text(\n                  \'数据已成功迁移至 SQLite 极速引擎！\',\n                  style: TextStyle(fontSize: 13, height: 1.4),\n                ),\n              ],\n            ],\n          ],\n        ),\n      ),\n    );\n  }\n}\n\n$after';
      
      file.writeAsStringSync(newContent);
      print('Fixed AboutScreen successfully.');
    }
  }
}
